CREATE TABLE stream_metrics (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,stream_id BIGINT UNSIGNED NOT NULL,health_score TINYINT UNSIGNED NOT NULL,status VARCHAR(20) NOT NULL,cpu_percent DECIMAL(6,2) NULL,memory_bytes BIGINT UNSIGNED NULL,encoding_speed DECIMAL(8,3) NULL,bitrate_kbps DECIMAL(10,2) NULL,dropped_frames INT UNSIGNED NULL,cpu_steal_percent DECIMAL(6,2) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CONSTRAINT fk_metric_stream FOREIGN KEY(stream_id) REFERENCES streams(id) ON DELETE CASCADE,INDEX idx_metric_stream_time(stream_id,created_at)) ENGINE=InnoDB;
